import{_ as e,o as n,c as s,a2 as a}from"./chunks/framework.D36jym0Z.js";const g=JSON.parse('{"title":"Core Runtime","description":"","frontmatter":{},"headers":[],"relativePath":"platform-concepts/core-runtime.md","filePath":"platform-concepts/core-runtime.md","lastUpdated":1784629191000}'),i={name:"platform-concepts/core-runtime.md"};function l(o,t,r,p,d,c){return n(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="core-runtime" tabindex="-1">Core Runtime <a class="header-anchor" href="#core-runtime" aria-label="Permalink to &quot;Core Runtime&quot;">​</a></h1><p>The LightMem2 core runtime is the <strong>host-independent execution engine</strong> that loads, manages, and runs plugins. It sits between the agent host and the plugins, providing a consistent environment regardless of which host the user is running.</p><h2 id="responsibilities" tabindex="-1">Responsibilities <a class="header-anchor" href="#responsibilities" aria-label="Permalink to &quot;Responsibilities&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Responsibility</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Plugin loading</strong></td><td style="text-align:left;">Discovers, validates, and loads plugins from configured directories</td></tr><tr><td style="text-align:left;"><strong>Lifecycle management</strong></td><td style="text-align:left;">Calls plugin hooks at the right time: install, enable, session start, session end, disable, uninstall</td></tr><tr><td style="text-align:left;"><strong>Configuration</strong></td><td style="text-align:left;">Merges host config, plugin config, and user overrides into a resolved configuration</td></tr><tr><td style="text-align:left;"><strong>Event routing</strong></td><td style="text-align:left;">Dispatches host events (messages, tool calls, session state changes) to plugins</td></tr><tr><td style="text-align:left;"><strong>Resource isolation</strong></td><td style="text-align:left;">Ensures plugins cannot interfere with each other or the host</td></tr></tbody></table><h2 id="how-it-fits-together" tabindex="-1">How It Fits Together <a class="header-anchor" href="#how-it-fits-together" aria-label="Permalink to &quot;How It Fits Together&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────┐</span></span>
<span class="line"><span>│              Agent Host                   │</span></span>
<span class="line"><span>│   (OpenClaw / Codex / Claude Code)        │</span></span>
<span class="line"><span>└────────────────┬─────────────────────────┘</span></span>
<span class="line"><span>                 │ Host events &amp; messages</span></span>
<span class="line"><span>┌────────────────▼─────────────────────────┐</span></span>
<span class="line"><span>│          Host Adapter                     │</span></span>
<span class="line"><span>│   Translates host-specific events         │</span></span>
<span class="line"><span>└────────────────┬─────────────────────────┘</span></span>
<span class="line"><span>                 │ Standardized events</span></span>
<span class="line"><span>┌────────────────▼─────────────────────────┐</span></span>
<span class="line"><span>│          Core Runtime                     │</span></span>
<span class="line"><span>│   Plugin lifecycle · Config · Routing     │</span></span>
<span class="line"><span>└────┬──────────────┬──────────────┬───────┘</span></span>
<span class="line"><span>     │              │              │</span></span>
<span class="line"><span>┌────▼───┐   ┌──────▼──────┐   ┌──▼────────┐</span></span>
<span class="line"><span>│Plugin A│   │  Plugin B   │   │ Plugin C   │</span></span>
<span class="line"><span>└────────┘   └─────────────┘   └───────────┘</span></span></code></pre></div><p>The core runtime never talks to the host directly — it always goes through the host adapter. This is what enables a plugin written once to run on any supported host.</p><h2 id="key-design-decisions" tabindex="-1">Key Design Decisions <a class="header-anchor" href="#key-design-decisions" aria-label="Permalink to &quot;Key Design Decisions&quot;">​</a></h2><ul><li><strong>No network dependency</strong>. The runtime runs entirely locally inside the host process or as a sidecar proxy.</li><li><strong>Plugin isolation</strong>. Plugins don&#39;t import each other; communication happens through well-defined events.</li><li><strong>Configuration cascade</strong>. Defaults → host config → plugin config → user overrides, with later layers taking precedence.</li></ul><h2 id="current-implementation" tabindex="-1">Current Implementation <a class="header-anchor" href="#current-implementation" aria-label="Permalink to &quot;Current Implementation&quot;">​</a></h2><p>The core runtime is implemented across these workspace packages:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Package</th><th style="text-align:left;">Purpose</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kernel</code></td><td style="text-align:left;">Shared types, interfaces, events, and runtime contracts</td></tr><tr><td style="text-align:left;"><code>runtime-core</code></td><td style="text-align:left;">Host-agnostic runtime engine and shared execution logic</td></tr><tr><td style="text-align:left;"><code>host-adapter</code></td><td style="text-align:left;">Shared host-adapter contracts and path-resolution interfaces</td></tr><tr><td style="text-align:left;"><code>layers/history</code></td><td style="text-align:left;">Canonical state, raw semantic turns, task registry</td></tr><tr><td style="text-align:left;"><code>layers/decision</code></td><td style="text-align:left;">Policy analysis, reduction/eviction decisions, estimator</td></tr><tr><td style="text-align:left;"><code>layers/memory</code> <span class="badge-experimental">experimental</span></td><td style="text-align:left;">Distillation and retrieval (in progress)</td></tr></tbody></table><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/LightMem2/platform-concepts/plugins">Plugins</a> — how plugins are structured</li><li><a href="/LightMem2/platform-concepts/plugin-lifecycle">Plugin Lifecycle</a> — the plugin state machine</li><li><a href="/LightMem2/platform-concepts/host-adapters">Host Adapters</a> — how hosts connect</li></ul>`,14)])])}const u=e(i,[["render",l]]);export{g as __pageData,u as default};
